diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 03bc0f16c893..0a97726f28ca 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -4508,7 +4508,7 @@ static Instruction *foldICmpOrXX(ICmpInst &I, const SimplifyQuery &Q,
 }

 static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
-                                  InstCombinerImpl &IC) {
+                                   InstCombinerImpl &IC) {
   Value *Op0 = I.getOperand(0), *Op1 = I.getOperand(1), *A;
   // Normalize xor operand as operand 0.
   CmpInst::Predicate Pred = I.getPredicate();
@@ -4528,6 +4528,15 @@ static Instruction *foldICmpXorXX(ICmpInst &I, const SimplifyQuery &Q,
       isKnownNonZero(A, Q.DL, /*Depth=*/0, Q.AC, Q.CxtI, Q.DT))
     return new ICmpInst(PredOut, Op0, Op1);

+  // If Op1 is a NOT (~X), then we have (~X ^ A) cmp ~X.
+  // ~(X ^ A) cmp ~X  -->  (X ^ A) swap(cmp) X
+  Value *X;
+  if (match(Op1, m_Xor(m_Value(X), m_AllOnes())) ||
+      match(Op1, m_c_Xor(m_Not(m_Value(X)), m_Specific(A)))) {
+    Value *NewXor = IC.Builder.CreateXor(X, A);
+    return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), NewXor, X);
+  }
+
   return nullptr;
 }

@@ -4832,6 +4841,21 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
   if (Instruction *R = foldICmpOrXX(I, Q, *this))
     return R;

+  // (~X ^ A) cmp ~Z --> (X ^ A) swap(cmp) Z
+  // ~X cmp (~Z ^ A) --> (Z ^ A) cmp X
+  {
+    Value *X, *A, *Z;
+    if (match(Op0, m_c_Xor(m_Not(m_Value(X)), m_Value(A))) &&
+        match(Op1, m_Not(m_Value(Z)))) {
+      Value *NewXor = Builder.CreateXor(X, A);
+      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), NewXor, Z);
+    }
+    if (match(Op0, m_Not(m_Value(X))) &&
+        match(Op1, m_c_Xor(m_Not(m_Value(Z)), m_Value(A)))) {
+      Value *NewXor = Builder.CreateXor(Z, A);
+      return new ICmpInst(Pred, NewXor, X);
+    }
+  }
   {
     // Try to remove shared multiplier from comparison:
     // X * Z u{lt/le/gt/ge}/eq/ne Y * Z

